// Output Sanitizer — enforces no URLs/markdown in final user-facing text
const raw = $input.first().json.output || '';

const clean = String(raw)
  .replace(/(?:https?:\/\/)?(?:www\.)?(?:calendly\.com|app\.cal\.com|cal\.com|acuityscheduling\.com)\/?[^\s\n]*/gi, '')
  .replace(/(?:https?:\/\/)?localhost(?::\d+)?\/?[^\s\n]*/gi, '')
  .replace(/(?:https?:\/\/|www\.)[^\s\n]+/gi, '')
  .replace(/\*\*/g, '')
  .replace(/(^|\s)[#*_`]{1,3}(?=\s|$)/g, ' ')
  .replace(/^\s*[-•]\s+/gm, '\n\n')
  .replace(/\s+-\s+/g, '\n\n')
  .split('\n')
  .map((line) => line.trim())
  .filter((line) => line && !/(?:\burl\b|\blink\b|\bhttp\b|\bwww\b|\bcalendly\b|\bcal\.com\b|رابط|لينك|localhost)/i.test(line))
  .join('\n')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/[ \t]{2,}/g, ' ')
  .replace(/^\s*[\-—]?\s*$/gm, '')
  .trim();

return [{
  json: {
    output: clean || 'تم تسجيل طلبك، والفريق سيتواصل معك قريباً لتأكيد التفاصيل.'
  }
}];

